import{_ as i,o as s,c as r,a3 as o}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"142. Discipline Specific Supervision Only Llews","description":"","frontmatter":{"title":"142. Discipline Specific Supervision Only Llews","eba":"Mental Health Services 2024-2028","topics":["discipline","education-pd"]},"headers":[],"relativePath":"ebas/mental-health/health-professionals/education-pd/142-discipline-specific-supervision-only-llews.md","filePath":"ebas/mental-health/health-professionals/education-pd/142-discipline-specific-supervision-only-llews.md"}'),n={name:"ebas/mental-health/health-professionals/education-pd/142-discipline-specific-supervision-only-llews.md"};function t(p,e,a,l,c,d){return s(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="_142-discipline-specific-supervision-only-llews" tabindex="-1">142. Discipline Specific Supervision Only Llews <a class="header-anchor" href="#_142-discipline-specific-supervision-only-llews" aria-label="Permalink to &quot;142. Discipline Specific Supervision Only Llews&quot;">​</a></h1><p><strong>142.1</strong> Introduction Discipline-specific supervision is an important mechanism to promote the learning, professional development and wellbeing of LLEWs Employees and the delivery of safe, high-quality care to consumers of mental health and wellbeing services.</p><p><strong>142.2</strong> Description</p><p><strong>(a)</strong> For the purposes of this clause, discipline-specific supervision is a process of supporting LLEW Employees to develop their practice through regular time spent in reflective discussion with experienced and knowledgeable colleagues who are adequately trained in providing supervision. Discipline-specific supervision for LLEWs includes but is not necessarily limited to reflective supervision, co- reflection and group supervision.</p><p><strong>(b)</strong> Discipline-specific supervision is not student supervision, line management/operational supervision, a line management tool, counselling, performance management, or a performance review process (and these processes will be conducted separately from discipline-specific supervision). Discipline-specific supervision will not be used as a method of surveillance.</p><p><strong>(c)</strong> Discipline-specific supervision will be guided by the following relevant frameworks:</p><p><strong>(i)</strong> Consumer Perspective Supervision: A framework for supporting the consumer workforce; and</p><p><strong>(ii)</strong> Carer Perspective Supervision: A framework for supporting the mental health family/carer Lived and Living Experience workforce (or their successors).</p><p><strong>142.3</strong> Entitlement</p><p><strong>(a)</strong> A maximum of two (2) hours per month of discipline-specific supervision is to be offered to all LLEWs Employees (including supervisors).</p><p><strong>(b)</strong> An Employee may request additional discipline-specific supervision. In deciding whether to approve their request, the Employer will consider the Employee’s reasons for requesting the additional supervision and the Employer’s operational requirements. This clause does not prevent an Employer offering additional supervision on a as needs basis.</p><p><strong>142.4</strong> Supervision arrangements</p><p><strong>(a)</strong> Supervision may be provided by a LLEWs Employee of the Employee’s choice from either within the service or where requested from an external source as determined by agreement between the Employee and the Employer. The external source may include existing reciprocal supervision arrangements with other mental health and wellbeing services. Whether the supervision arrangement is internal or external, it will be delivered by a supervisor who comes from LLEWs.</p><p><strong>(b)</strong> All Supervisors must have received supervision and undertaken supervision training acceptable to the Employer.</p><p><strong>(c)</strong> For Employees classified at Grade 3 or below, the internal supervisor will be of a higher classification to the employee(s) they are supervising. Discipline-specific supervision will not be provided by the Employee’s line manager/supervisor.</p><p><strong>(d)</strong> An Employee may request a change of supervisor at any time.</p><p><strong>(e)</strong> Supervision will occur only on rostered time, at a time mutually agreed between the Employee and Employer. Where the supervision is not available either internally or via and existing reciprocal supervision arrangements with other mental health and wellbeing services or other agreed services (eg The Collective) the Employer will be responsible for meeting the reasonable costs of supervision.</p><p><strong>142.5</strong> Supervision training Where an Employer and Employee agree for the Employee to become a discipline-specific supervisor under this clause 142, the Employee will be provided access to appropriate supervision training before they start delivering supervision. The particular training undertaken will be agreed between the Employee and Employer. The training will be completed on paid time. Requests from Employees to undertake supervision training will be directed to the Employee’s line manager and will be responded to within 14 days.</p><p><strong>142.6</strong> Access to record of discipline-specific supervisors Employers will maintain and make available to Employees a record of trained supervisors who, subject to their availability, are able to provide LLEWs supervision to Employees.</p>',19)])])}const h=i(n,[["render",t]]);export{m as __pageData,h as default};
